test-code.code:
fun check(x: Int): String {
    if (x > 0) return "positive"
    return ""
}

fun check(x: Int): String {
    return if (x > 0) "positive" else "non-positive"
}

fun check(a: Int, b: Int): String {
    if (a > 0) {
        if (b > 0) return "both positive"
    }
    return ""
}

fun sumPositive(items: List<Int>): Int {
    var sum = 0
    for (item in items) {
        if (item > 0) sum += item
    }
    return sum
}

fun label(n: Int): String = when {
    n > 0 -> "positive"
    else  -> "other"
}

fun describe(x: Int, y: Int): String {
    if (x > 0) {
        return when {
            y > 0 -> "both positive"
            else  -> "only x"
        }
    }
    return "neither"
}
